let forma = prompt('Qual a forma ("1, 2, 3")');
let l1;
let L2;
let area;
let raio;

switch (forma) {
    case "1":
        l1 = +prompt('Quanto mede o lado 1')
        l2 = +prompt('Quanto mede o lado 2')
        area = l1 * l2;
        alert(`a area mede ${area}`)
        break;

    case "2":
        l1 = +prompt('Quanto mede o lado ')
        area = l1 * l1;
        alert(`a area mede ${area}`)
        break;

        case "3":
        raio = +prompt('Quanto mede o raio')
        area = raio*3. 
        alert(`a area mede ${area}`)
        break;

    default:
        alert("Forma invalida");
}

